args.sparql:
SELECT ?coach ?coachLabel ?age
WHERE {
  ?team wdt:P3235 wd:Q401278 .
  ?coach wdt:P569 ?birthDate .
  ?coach p:P286 ?posStatement .
  ?posStatement ps:P286 ?team ;
             pq:P580 ?startDate .
  FILTER(?startDate >= "2015-01-01"^^xsd:date)
  BIND((YEAR(?startDate) - YEAR(?birthDate)) AS ?age)
  OPTIONAL { ?coach rdfs:label ?coachLabel . FILTER(LANG(?coachLabel) = "en") }
}
ORDER BY ?age
LIMIT 5

